Kaj izpiše navedeni program? 
public class NalogaArgumenti { 
   static int metoda(int [] z){ 
      z[2]=50; 
      return 1; 
   } 
   static int metoda1(int a){ 
      a=50; 
      return 1; 
   } 
   public static void main(String[] args) { 
      int [] x={1,2,3,4}; 
      metoda(x); 
      System.out.println(x[2]);  
      int y = 2; 
      metoda1(y); 
      System.out.println(y);  
} 
}

